funnel_plot(
  .data = covid19,
  numerator = Death,
  denominator = Positive,
  group = `Sub-district`,
  data_type = "PR",     #&lt;&lt;
  xrange = c(0, 6500),  #&lt;&lt;
  yrange = c(0, 0.05)   #&lt;&lt;
